import{_ as e,o as r,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6442_光聖/20260504/F17_籌碼分佈與法人動態分析.md","filePath":"審計報告庫/財務審計/6442_光聖/20260504/F17_籌碼分佈與法人動態分析.md"}'),l={name:"審計報告庫/財務審計/6442_光聖/20260504/F17_籌碼分佈與法人動態分析.md"};function i(n,a,h,s,d,_){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="f17-籌碼分佈與法人動態分析" tabindex="-1">F17: 籌碼分佈與法人動態分析 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析&quot;">​</a></h1><blockquote><p>標的公司：6442 光聖 | 基準日期：20260504</p></blockquote><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p><h2 id="🎯-專家直斷-40-80-字" tabindex="-1">🎯 專家直斷（40-80 字） <a class="header-anchor" href="#🎯-專家直斷-40-80-字" aria-label="Permalink to &quot;🎯 專家直斷（40-80 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：外資持股 66.8%→65.4% 近一月微幅減持，千張大戶 38-40% 仍穩定。惟股東人數年增 227%，籌碼由集中轉分散為主要結構風險。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：2026/4/30</li></ul><h2 id="📊-診斷評級-80-150-字" tabindex="-1">📊 診斷評級（80-150 字） <a class="header-anchor" href="#📊-診斷評級-80-150-字" aria-label="Permalink to &quot;📊 診斷評級（80-150 字）&quot;">​</a></h2><p>三大法人動向（近一月）：外資小幅賣超約 115 萬股（持股 66.8%→65.4%），投信買賣超不明顯，自營商無顯著動作。法人合計未有連續性大額買超或賣超，資金動能中性。千張大戶從 14 人（2025/1）降至 10-11 人（2026/4），頂層籌碼小幅鬆散但絕對持股比例仍高。融資餘額若從公開資料推估不高，無融資斷頭壓力。</p><p><strong>評級：B（持平）</strong> — 法人無明顯鎖碼動作，籌碼由集中轉為分散。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>法人動能：</strong> 外資持股變動：66.83%→66.44%→66.10%→65.37%（連續四周微減）。外資在目前價位（PE 區間 63-121 倍）採取獲利了結或減持操作，但速度緩慢，推測為被動調整而非看空。</p><p><strong>籌碼結構變化：</strong> 散戶（1-999 股）人數從 14,380 人（2025/4）暴增至 45,507 人（2026/4），一年內增加 216%。而千張大戶份額從 44.82% 降至 38.44%（−6.38pp）。典型「派發期」特徵——高價位吸引散戶追價而大戶逐步釋出。</p><p><strong>法說會後效應：</strong> 2026/3/12 法說會後散戶加速湧入，可能是媒體報導 EPS 23.46 吸引散戶進場。但外資與大戶未同步追買。</p><h2 id="💡-專家評析-200-450-字" tabindex="-1">💡 專家評析（200-450 字） <a class="header-anchor" href="#💡-專家評析-200-450-字" aria-label="Permalink to &quot;💡 專家評析（200-450 字）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li>外資連續四周減持（持股從 66.8% 降至 65.4%），配合散戶人數暴增 227%，形成典型的「法人出、散戶接」派發結構。若此趨勢持續，將壓抑股價的上漲動能。</li><li>股東人數年增 227% 代表股票高度分散化，籌碼從強勢手大量流向弱勢手群體。後續股價上漲需要更大的資金動能才能推動，技術面不利。</li><li>融資餘額雖不高，但散戶大量湧入後若遭遇股價回檔，可能引發融資多殺多效應，加速下跌速度。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li>外資減持幅度不到 2%，更多是價位過高後被動調整而非系統性看空，尚不構成趨勢性撤退。</li><li>千張大戶絕對持股 38% 仍在集中水準，核心股東群體並未潰散。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>籌碼面已出現「高檔派發」的早期信號，雖尚未到危險程度，但多空力量正在轉變，建議降低對股價短期動能的預期。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>FinMind TaiwanStockHolding（外資持股）</li><li>FinMind TaiwanStockShareholdingSpread</li><li>數據查詢日期：2026-05-04</li></ul>',23)])])}const p=e(l,[["render",i]]);export{u as __pageData,p as default};
